#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00588Custom {
public:
  __aicore__ inline KernelCa6k00588Custom() {}

  __aicore__ inline void Init(GM_ADDR x, GM_ADDR gamma, GM_ADDR beta,
                              GM_ADDR running_mean, GM_ADDR running_var,
                              GM_ADDR y,
                              uint32_t totalN, uint32_t totalC, uint32_t totalSpatial,
                              uint32_t tileBatch, uint32_t tileSpatial, float eps) {
    totalN_ = totalN;
    totalC_ = totalC;
    totalSpatial_ = totalSpatial;
    tileBatch_ = tileBatch;
    tileSpatial_ = tileSpatial;
    eps_ = eps;

    xGm_.SetGlobalBuffer((__gm__ float *)x, totalN_ * totalC_ * totalSpatial_);
    gammaGm_.SetGlobalBuffer((__gm__ float *)gamma, totalC_);
    betaGm_.SetGlobalBuffer((__gm__ float *)beta, totalC_);
    runningMeanGm_.SetGlobalBuffer((__gm__ float *)running_mean, totalC_);
    runningVarGm_.SetGlobalBuffer((__gm__ float *)running_var, totalC_);
    yGm_.SetGlobalBuffer((__gm__ float *)y, totalN_ * totalC_ * totalSpatial_);

    pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileBatch_ * tileSpatial_ * sizeof(float));
    pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileBatch_ * tileSpatial_ * sizeof(float));
    pipe_.InitBuffer(meanLocal_, 1, totalC_ * sizeof(float));
    pipe_.InitBuffer(varLocal_, 1, totalC_ * sizeof(float));
    pipe_.InitBuffer(gammaLocal_, 1, totalC_ * sizeof(float));
    pipe_.InitBuffer(betaLocal_, 1, totalC_ * sizeof(float));
  }

  __aicore__ inline void Process() {
    if (totalN_ == 0 || totalC_ == 0 || totalSpatial_ == 0) return;

    // Copy per-channel values to local memory
    AscendC::LocalTensor<float> meanLocal = meanLocal_.AllocTensor<float>();
    AscendC::LocalTensor<float> varLocal = varLocal_.AllocTensor<float>();
    AscendC::LocalTensor<float> gammaLocal = gammaLocal_.AllocTensor<float>();
    AscendC::LocalTensor<float> betaLocal = betaLocal_.AllocTensor<float>();

    AscendC::DataCopy(meanLocal, runningMeanGm_, totalC_);
    AscendC::DataCopy(varLocal, runningVarGm_, totalC_);
    AscendC::DataCopy(gammaLocal, gammaGm_, totalC_);
    AscendC::DataCopy(betaLocal, betaGm_, totalC_);

    // Process each channel tile by tile
    for (uint32_t c = 0; c < totalC_; c++) {
      float mean = meanLocal(c);
      float var = varLocal(c);
      float invStd = 1.0f / sqrt(var + eps_);
      float gamma = gammaLocal(c);
      float beta = betaLocal(c);

      for (uint32_t b = 0; b < totalN_; b += tileBatch_) {
        uint32_t curBatch = tileBatch_;
        if (b + curBatch > totalN_) curBatch = totalN_ - b;

        for (uint32_t s = 0; s < totalSpatial_; s += tileSpatial_) {
          uint32_t curSpatial = tileSpatial_;
          if (s + curSpatial > totalSpatial_) curSpatial = totalSpatial_ - s;

          uint32_t tileElems = curBatch * curSpatial;
          uint32_t offset = b * totalC_ * totalSpatial_ + c * totalSpatial_ + s;

          // Load x tile
          AscendC::LocalTensor<float> xTile = inQueueX_.AllocTensor<float>();
          AscendC::DataCopy(xTile, xGm_[offset], tileElems);
          inQueueX_.EnQue(xTile);
          AscendC::LocalTensor<float> xDeq = inQueueX_.DeQue<float>();

          // Compute y = gamma * (x - mean) * invStd + beta
          AscendC::LocalTensor<float> yTile = outQueueY_.AllocTensor<float>();
          for (uint32_t i = 0; i < tileElems; i++) {
            yTile(i) = gamma * (xDeq(i) - mean) * invStd + beta;
          }
          outQueueY_.EnQue(yTile);
          inQueueX_.FreeTensor(xDeq);

          // Store y tile
          AscendC::LocalTensor<float> yDeq = outQueueY_.DeQue<float>();
          AscendC::DataCopy(yGm_[offset], yDeq, tileElems);
          outQueueY_.FreeTensor(yDeq);
        }
      }
    }

    meanLocal_.FreeTensor(meanLocal);
    varLocal_.FreeTensor(varLocal);
    gammaLocal_.FreeTensor(gammaLocal);
    betaLocal_.FreeTensor(betaLocal);
  }

private:
  AscendC::TPipe pipe_;
  AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
  AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> meanLocal_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> varLocal_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> gammaLocal_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> betaLocal_;

  AscendC::GlobalTensor<float> xGm_;
  AscendC::GlobalTensor<float> gammaGm_;
  AscendC::GlobalTensor<float> betaGm_;
  AscendC::GlobalTensor<float> runningMeanGm_;
  AscendC::GlobalTensor<float> runningVarGm_;
  AscendC::GlobalTensor<float> yGm_;

  uint32_t totalN_ {0};
  uint32_t totalC_ {0};
  uint32_t totalSpatial_ {0};
  uint32_t tileBatch_ {0};
  uint32_t tileSpatial_ {0};
  float eps_ {1e-5};
};

extern "C" __global__ __aicore__ void ca6k00588_custom(GM_ADDR x, GM_ADDR gamma, GM_ADDR beta,
                                                         GM_ADDR running_mean, GM_ADDR running_var,
                                                         GM_ADDR y,
                                                         GM_ADDR workspace, GM_ADDR tiling) {
  GET_TILING_DATA(tiling_data, tiling);
  KernelCa6k00588Custom op;
  op.Init(x, gamma, beta, running_mean, running_var, y,
          tiling_data.totalN, tiling_data.totalC,
          tiling_data.totalSpatial,
          tiling_data.tileBatch, tiling_data.tileSpatial,
          tiling_data.eps);
  op.Process();
}
